Code.Terraform:
```hcl
# 为该密钥启用轮换
resource "aws_secretsmanager_secret_rotation" "<example_resource_name>" {
  secret_id          = "<example_resource_id>"  # 关键：目标 secret
  rotation_lambda_arn = "<example_resource_id>" # 严重：用于轮换的 Lambda ARN

  rotation_rules {                          
    automatically_after_days = 30            # 关键：在允许的天数内轮换
  }
}
```
